CREATE SCHEMA IF NOT EXISTS fixture_wrong_field_names_src;
SET search_path TO fixture_wrong_field_names_src;

CREATE TABLE ansprechpartner ( ap_id text PRIMARY KEY, vorname text, nachname text, email_adresse text, telefonnummer text, position text, funktion text, sprache text, kunde text );


CREATE TABLE assets ( asset_id text PRIMARY KEY, bezeichnung text, seriennr text, garantie_bis text, kd_ref text, projekt_ref text );


CREATE TABLE chancen ( chance_id text PRIMARY KEY, bezeichnung text, phase text, abschlussdatum text, volumen double precision, waehrung text, kd_nr text );


CREATE TABLE kunden ( kunden_nr text PRIMARY KEY, firmenname text, erp_nummer text, kategorie text, gebiet text, branche text, webseite text, ort text, land text );


CREATE TABLE proj ( proj_id text PRIMARY KEY, name text, status text, go_live text, kd text, opp text );

